var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"크르르르르…….","JPN":"グルルルル……","ENG":"Grrrrr...","TWN":"嗚喔喔喔喔……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"날 찾아온다면, 당연히 자랑스러운 조국에서 보낸 녀석들일 줄 알았는데.","JPN":"誰か面と向かいにくるんなら、クソ誇らしい祖国からだろうと思ってたけど。","ENG":"Honestly, if someone came to hunt me down, I figured it'd be someone sent from my proud homeland.","TWN":"如果來找我的話，我以為肯定是我那自豪的祖國派來的人呢。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 이거 어쩌나? 침식체랑 나뒹구는 건 내 취향이 아닌 걸?","JPN":"残念だったな。こっちは侵食体と喧嘩なんて好みじゃないんだ。","ENG":"But sorry to say, messing around with a C.O. isn't really my thing.","TWN":"但是這個怎麼辦？我可不喜歡和侵蝕體糾纏在一起。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리도 네게 볼 일 없다. 녹색 머리 여자.","JPN":"オレタチモ、オマエニ用ハナイ。緑ノ髪ノ女。","ENG":"We don't have any business with you, green-haired woman.","TWN":"我們也不想見你，綠頭髮的女人。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんだと？","ENG":"W-what?","TWN":"什，什麼？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리가 찾는 것은. 그리운 근원. 모든 것의 고향.","JPN":"オレタチガ探シテイルノハ、懐カシイ根源。全テノ故郷。","ENG":"What we're searching for. The origin. Home of everything.","TWN":"我們尋找的是——懷念的根源，一切的故鄉。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"너와 함께 있던 덩치 작은 여자. 지금 어디 있지?","JPN":"オマエト共ニイタ小サイ女。ドコニイル？","ENG":"The small girl who was with you. Where is she now?","TWN":"和你在一起的那個小個子女人，現在在哪裡？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나랑 같이 다니는 덩치 작은 녀석?","JPN":"私と共にいた小さいやつ？","ENG":"The small girl I was with?","TWN":"跟我一起走的小個子？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"펠리세트가 뭐 어쨌다고? 침식체가 걔를 왜 찾아? 걔 쥐뿔도 없는데?","JPN":"フェリセットのことか？　侵食体があいつに何の用がある？　あいつは大したやつじゃないぞ？","ENG":"You mean Félicette? What do you want with her? She's not special or anything?","TWN":"費莉塞特怎麼了？侵蝕體為什麼找她？她什麼都沒有啊？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 이름. 인간의 기준. 그런 건 모른다.","JPN":"人間ノ名前。人間ノ基準。ソンナコトハ知ラナイ。","ENG":"Human name. Human standards. I don't know.","TWN":"人類的名字，人類的標準，這些我都不知道。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"덩치가 작은 여자. 나무로부터 내려온 존재…….","JPN":"小サイ女。木ヨリ送ラレタ存在……","ENG":"Small girl. Descended from the tree...","TWN":"身材嬌小的女子。從樹上降臨的存在……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나 참, 침식체 주제에 아주 게을러 빠졌구만?","JPN":"ったく、侵食体のくせに怠けやがって。","ENG":"Unbelievable. For a C.O., you're pretty lazy, huh?","TWN":"哎呀，作為侵蝕體竟然這麼懶惰？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이름도 모르면서 누가 누굴 찾는다는 거야, 이 멍청아!","JPN":"名前も知らずに人探しなんかできるもんか、バカ！","ENG":"You don't even know her name. How do you expect to find her, you idiot?","TWN":"連名字都不知道，誰找誰啊，你這個笨蛋！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"동포를 통해서. 정보를 전달받았다.","JPN":"仲間ガ、情報ヲクレタ。","ENG":"Through my kind. Received information.","TWN":"透過同胞，收到了資訊。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"너희 셋. 계속 함께였다. 그러니까 알 수 있다.","JPN":"オマエタチ3人。ズット一緒ダッタ。ダカラワカル。","ENG":"You three. Always together. So we know.","TWN":"你們三個，一直在一起，所以能知道。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 셋이라고?","JPN":"待て、3人だと？","ENG":"Wait, three?","TWN":"等等，三個……？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어디보자… 나랑 꼬맹이랑, 스키너…….","JPN":"どれ……私とおこちゃまと、スキナー……","ENG":"Let's see... There's me, little kid, and Skinner...","TWN":"讓我看看……我和小鬼，還有史金納……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니다. 선수니까 미나까지 포함인가? 그런데 걔 덩치가 작지는……","JPN":"いや、選手だからミナも含めてか？　でもあいつは別に小柄じゃ……","ENG":"Or maybe I should count Mina too? But she's not exactly small...","TWN":"不是。因為是選手，所以也包括米娜嗎？不過她的體型也不小……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Wait what?","TWN":"咦？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기본 포지션은 최소 한 명씩 들어가는 게 엔트리의 기본 규칙이거든.","JPN":"基本的に、ポジションごとに最低1名ずつ入るのがエントリーの条件でね。","ENG":"The rules for participation require that we have at least one of each position.","TWN":"因為參賽的基本規則，是每個基本位置上都至少要有一個人啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"디펜더는 여기 사이코 꼬맹이, 그리고 레인저는 나.","JPN":"ディフェンダーはこっちのサイコガキ、それにレンジャーは私。","ENG":"Psycho kid here's our defender, and I'm the ranger.","TWN":"護衛是這個小瘋子，突擊隊員是我。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"서포터는 스키너가 있으니까 제외. 타워랑 시즈는 예외.","JPN":"サポーターはスキナーがいるからいいとして。タワーとシージは例外。","ENG":"For our supporter, we have Skinner. Towers and sieges are not mandatory.","TWN":"輔助有史金納，所以不算，要塞和攻城也不是必須的。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"남은 건 후방 교란을 맡을 스트라이커랑…. 저격수란 뜻이지.","JPN":"残りは後方を攪乱させるストライカーと……スナイパーなんだ。","ENG":"So all that remains is a striker who can flank behind enemy lines... and a sniper.","TWN":"剩下的就是負責擾亂敵人後方的前鋒和……狙擊手。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 입사하자마자 염치 없는 부탁이긴 한데요.","JPN":"それで入社そうそうに申し訳ないんですけど。","ENG":"And I know I'm asking a lot as soon as I joined the company, but...","TWN":"所以剛入職就要厚著臉皮請公司幫忙。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저격수 한 명 소개해 주실 수 없을까요, 사장님?","JPN":"スナイパーを1人紹介していただけませんか？　社長。","ENG":"Boss, could you introduce us to a sniper?","TWN":"老闆能幫我們介紹一名狙擊手嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};